<script setup>
import { computed, reactive, ref } from 'vue';
import { Head, Link } from '@inertiajs/vue3';
import axios from 'axios';
const props=defineProps({participations:Array,courses:Array});const courseItems=ref(JSON.parse(JSON.stringify(props.courses||[])));const participationFor=(course)=>props.participations.find(p=>p.projekt_id===course.project_id);const enrollmentFor=(course)=>course.enrollments?.find(e=>e.project_person_id===participationFor(course)?.id);const completed=(enrollment,lesson)=>Boolean(enrollment?.progress?.find(p=>p.lesson_id===lesson.id)?.completed);const percent=(course)=>{const e=enrollmentFor(course);if(!e||!course.lessons?.length)return 0;return Math.round(course.lessons.filter(l=>completed(e,l)).length/course.lessons.length*100)};const enroll=async(course)=>{const p=participationFor(course);const r=await axios.post(route('participant-portal.learning.enroll',course.id),{project_person_id:p.id});course.enrollments=[{...r.data.enrollment,progress:[],submissions:[]}];};const toggle=async(course,lesson,value)=>{const e=enrollmentFor(course);const r=await axios.put(route('participant-portal.learning.progress.update',{enrollment:e.id,lesson:lesson.id}),{completed:value});e.status=r.data.enrollment.status;e.completed_at=r.data.enrollment.completed_at;const existing=e.progress?.find(p=>p.lesson_id===lesson.id);if(existing)Object.assign(existing,r.data.progress);else(e.progress||(e.progress=[])).push(r.data.progress);};
const submissionForms=reactive({});const submissionFor=(course,assignment)=>assignment.submissions?.find(item=>item.enrollment_id===enrollmentFor(course)?.id);const submissionForm=(course,assignment)=>submissionForms[`${course.id}-${assignment.id}`]||(submissionForms[`${course.id}-${assignment.id}`]={text_answer:submissionFor(course,assignment)?.text_answer||'',file:null});const submitAssignment=async(course,assignment)=>{const form=submissionForm(course,assignment);const data=new FormData();if(form.text_answer)data.append('text_answer',form.text_answer);if(form.file)data.append('file',form.file);const r=await axios.post(route('participant-portal.learning.assignments.submit',assignment.id),data,{headers:{'Content-Type':'multipart/form-data'}});const existing=submissionFor(course,assignment);if(existing)Object.assign(existing,r.data.submission);else(assignment.submissions||(assignment.submissions=[])).push(r.data.submission);form.file=null;};
</script>
<template><Head title="Kurse"/><main class="min-h-screen bg-sky-50 px-5 py-8"><div class="mx-auto max-w-5xl space-y-6"><header class="flex justify-between"><div><p class="text-xs font-semibold uppercase tracking-widest text-zbb">Matrix Teilnehmerportal</p><h1 class="text-2xl font-bold">Kurse und Lernen</h1></div><Link :href="route('participant-portal.dashboard')" class="rounded border bg-white px-4 py-2 text-sm">Dashboard</Link></header>
<article v-for="course in courseItems" :key="course.id" class="rounded-2xl border bg-white p-6 shadow-sm"><div class="flex justify-between gap-3"><div><h2 class="text-lg font-semibold">{{ course.title }}</h2><p class="text-sm text-gray-500">{{ course.project?.name }}</p><p class="mt-2 text-gray-600">{{ course.description }}</p></div><div class="text-right"><p class="text-2xl font-bold text-zbb">{{ percent(course) }} %</p><p class="text-xs text-gray-500">Fortschritt</p></div></div><button v-if="!enrollmentFor(course)&&course.self_enrollment" class="mt-4 rounded bg-zbb px-4 py-2 text-white" @click="enroll(course)">Jetzt teilnehmen</button><p v-else-if="!enrollmentFor(course)" class="mt-4 text-sm text-gray-500">Eine Einschreibung durch Ihre Betreuung ist erforderlich.</p><template v-else><div class="mt-5 space-y-3"><label v-for="lesson in course.lessons" :key="lesson.id" class="block rounded-xl border p-4"><span class="flex items-start gap-3"><input type="checkbox" class="mt-1 rounded text-zbb" :checked="completed(enrollmentFor(course),lesson)" @change="toggle(course,lesson,$event.target.checked)"/><span><strong>{{ lesson.title }}</strong><span class="mt-2 block whitespace-pre-line text-sm text-gray-600">{{ lesson.content }}</span></span></span></label><p v-if="!course.lessons.length" class="text-sm text-gray-500">Noch keine Lektionen veröffentlicht.</p></div><section v-if="course.materials?.length" class="mt-6"><h3 class="font-semibold">Materialien</h3><div class="mt-2 grid gap-2 sm:grid-cols-2"><a v-for="material in course.materials" :key="material.id" :href="route('participant-portal.learning.materials.download',material.id)" class="rounded border bg-gray-50 p-3 text-sm text-zbb">{{ material.title }}<span class="block text-xs text-gray-500">{{ material.original_name }} · {{ Math.ceil(material.size/1024) }} KB</span></a></div></section><section v-if="course.assignments?.length" class="mt-6"><h3 class="font-semibold">Aufgaben und Abgaben</h3><article v-for="assignment in course.assignments" :key="assignment.id" class="mt-3 rounded-xl border p-4"><div class="flex justify-between gap-3"><div><h4 class="font-semibold">{{ assignment.title }}</h4><p class="mt-1 whitespace-pre-wrap text-sm text-gray-600">{{ assignment.instructions }}</p></div><span v-if="assignment.due_at" class="text-xs text-red-600">Fällig: {{ new Date(assignment.due_at).toLocaleString('de-DE') }}</span></div><div class="mt-3 grid gap-3"><textarea v-if="assignment.allow_text" v-model="submissionForm(course,assignment).text_answer" rows="3" placeholder="Ihre Antwort" class="rounded border-gray-300 text-sm"></textarea><input v-if="assignment.allow_file" type="file" class="text-sm" @change="submissionForm(course,assignment).file=$event.target.files[0]"/><button class="w-fit rounded bg-zbb px-4 py-2 text-sm text-white" @click="submitAssignment(course,assignment)">{{ submissionFor(course,assignment)?'Abgabe aktualisieren':'Abgeben' }}</button></div><div v-if="submissionFor(course,assignment)" class="mt-3 rounded bg-gray-50 p-3 text-sm"><p>Status: {{ submissionFor(course,assignment).status }}</p><a v-if="submissionFor(course,assignment).path" :href="route('participant-portal.learning.submissions.download',submissionFor(course,assignment).id)" class="text-zbb">Eigene Datei herunterladen</a><p v-if="submissionFor(course,assignment).feedback" class="mt-2">Feedback: {{ submissionFor(course,assignment).feedback }}</p><p v-if="submissionFor(course,assignment).score!==null" class="font-semibold">Punkte: {{ submissionFor(course,assignment).score }} / {{ assignment.max_points||'–' }}</p></div></article></section></template></article><p v-if="!courseItems.length" class="rounded-2xl border bg-white p-8 text-center text-gray-500">Keine veröffentlichten Kurse verfügbar.</p></div></main></template>
